package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  @Test
  void testSerializeNulls() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    // Initially serializeNulls should be false (default)
    boolean initialSerializeNulls = (boolean) getPrivateField(builder, "serializeNulls");
    assertFalse(initialSerializeNulls);

    // Call serializeNulls method
    GsonBuilder returnedBuilder = builder.serializeNulls();

    // The method should return the same instance (this)
    assertSame(builder, returnedBuilder);

    // After calling serializeNulls, the field should be true
    boolean updatedSerializeNulls = (boolean) getPrivateField(builder, "serializeNulls");
    assertTrue(updatedSerializeNulls);
  }

  private Object getPrivateField(Object instance, String fieldName) throws Exception {
    java.lang.reflect.Field field = instance.getClass().getDeclaredField(fieldName);
    field.setAccessible(true);
    return field.get(instance);
  }
}
